     1→/**
     2→ * 마크다운 파서 - 외부 라이브러리 없이 직접 구현
     3→ * 지원: 제목, 굵게, 기울임, 인라인 코드, 코드블록, 링크, 이미지,
     4→ *       순서/비순서 목록(중첩), 인용문(중첩), 수평선, 문단, 줄바꿈, 이스케이프
     5→ */
     6→
     7→const MarkdownParser = (() => {
     8→  // 이스케이프 처리가 필요한 HTML 특수문자
     9→  function escapeHtml(text) {
    10→    return text
    11→      .replace(/&/g, '&amp;')
    12→      .replace(/</g, '&lt;')
    13→      .replace(/>/g, '&gt;')
    14→      .replace(/"/g, '&quot;')
    15→      .replace(/'/g, '&#39;');
    16→  }
    17→
    18→  // 백슬래시 이스케이프 처리
    19→  function processEscapes(text) {
    20→    return text.replace(/\\([\\`*_{}\[\]()#+\-.!~|])/g, (_, char) => {
    21→      return `&#x${char.charCodeAt(0).toString(16)};`;
    22→    });
    23→  }
    24→
    25→  // 인라인 요소 파싱 (굵게, 기울임, 인라인 코드, 링크, 이미지)
    26→  function parseInline(text) {
    27→    // 백슬래시 이스케이프 먼저 처리
    28→    text = processEscapes(text);
    29→
    30→    // 인라인 코드를 플레이스홀더로 먼저 교체
    31→    // → 이후 bold/italic 패턴이 코드 내부에 적용되지 않도록 보호
    32→    const inlineCodes = [];
    33→    text = text.replace(/``(.+?)``/g, (_, code) => {
    34→      inlineCodes.push(`<code>${escapeHtml(code)}</code>`);
    35→      return `\x00IC${inlineCodes.length - 1}\x00`;
    36→    });
    37→    text = text.replace(/`([^`]+)`/g, (_, code) => {
    38→      inlineCodes.push(`<code>${escapeHtml(code)}</code>`);
    39→      return `\x00IC${inlineCodes.length - 1}\x00`;
    40→    });
    41→
    42→    // 일반 텍스트의 HTML 특수문자 이스케이프
    43→    // (링크/이미지/코드 처리 전에 & < > 를 안전하게 변환)
    44→    text = text.replace(/&(?!#?\w+;)/g, '&amp;');
    45→    text = text.replace(/</g, '&lt;');
    46→    text = text.replace(/>/g, '&gt;');
    47→
    48→    // 이미지 (링크보다 먼저 처리)
    49→    text = text.replace(/!\[([^\]]*)\]\(([^)]+?)(?:\s+"([^"]*)")?\)/g, (_, alt, src, title) => {
    50→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    51→      return `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"${titleAttr}>`;
    52→    });
    53→
    54→    // 링크
    55→    text = text.replace(/\[([^\]]+)\]\(([^)]+?)(?:\s+"([^"]*)")?\)/g, (_, label, href, title) => {
    56→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    57→      return `<a href="${escapeHtml(href)}"${titleAttr}>${label}</a>`;
    58→    });
    59→
    60→    // 굵게 + 기울임 (***text*** 또는 ___text___)
    61→    text = text.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
    62→    text = text.replace(/___(.+?)___/g, '<strong><em>$1</em></strong>');
    63→
    64→    // 굵게 (**text** 또는 __text__)
    65→    text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    66→    text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');
    67→
    68→    // 기울임 (*text* 또는 _text_)
    69→    text = text.replace(/\*([^*]+)\*/g, '<em>$1</em>');
    70→    text = text.replace(/_([^_]+)_/g, '<em>$1</em>');
    71→
    72→    // 취소선 (~~text~~)
    73→    text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');
    74→
    75→    // 자동 URL 링크 — href/src 속성 안의 URL은 제외 (lookbehind로 " = ' 뒤 URL 건너뜀)
    76→    text = text.replace(/(?<![="'(])(https?:\/\/[^\s&<>"]+)/g, '<a href="$1">$1</a>');
    77→
    78→    // 인라인 코드 플레이스홀더 복원
    79→    text = text.replace(/\x00IC(\d+)\x00/g, (_, i) => inlineCodes[parseInt(i)]);
    80→
    81→    return text;
    82→  }
    83→
    84→  // 코드블록 추출 (파싱 전 플레이스홀더로 대체)
    85→  function extractCodeBlocks(lines) {
    86→    const codeBlocks = [];
    87→    const result = [];
    88→    let inCodeBlock = false;
    89→    let codeLines = [];
    90→    let codeLang = '';
    91→
    92→    for (let i = 0; i < lines.length; i++) {
    93→      const line = lines[i];
    94→      const fenceMatch = line.match(/^(`{3,}|~{3,})\s*(\w*)/);
    95→
    96→      if (!inCodeBlock && fenceMatch) {
    97→        inCodeBlock = true;
    98→        codeLang = fenceMatch[2] || '';
    99→        codeLines = [];
   100→      } else if (inCodeBlock && line.match(/^(`{3,}|~{3,})\s*$/)) {
   101→        inCodeBlock = false;
   102→        const placeholder = `\x00CODE_BLOCK_${codeBlocks.length}\x00`;
   103→        const langLabel = codeLang ? `<span class="code-lang">${escapeHtml(codeLang)}</span>` : '';
   104→        const codeContent = escapeHtml(codeLines.join('\n'));
   105→        codeBlocks.push(`<pre>${langLabel}<code class="language-${escapeHtml(codeLang)}">${codeContent}</code></pre>`);
   106→        result.push(placeholder);
   107→        codeLines = [];
   108→        codeLang = '';
   109→      } else if (inCodeBlock) {
   110→        codeLines.push(line);
   111→      } else {
   112→        result.push(line);
   113→      }
   114→    }
   115→
   116→    // 닫히지 않은 코드블록 처리
   117→    if (inCodeBlock && codeLines.length > 0) {
   118→      const placeholder = `\x00CODE_BLOCK_${codeBlocks.length}\x00`;
   119→      const langLabel = codeLang ? `<span class="code-lang">${escapeHtml(codeLang)}</span>` : '';
   120→      const codeContent = escapeHtml(codeLines.join('\n'));
   121→      codeBlocks.push(`<pre>${langLabel}<code class="language-${escapeHtml(codeLang)}">${codeContent}</code></pre>`);
   122→      result.push(placeholder);
   123→    }
   124→
   125→    return { lines: result, codeBlocks };
   126→  }
   127→
   128→  // 목록 파싱 (중첩 지원)
   129→  function parseList(lines, startIndex) {
   130→    const items = [];
   131→    let i = startIndex;
   132→    const firstLine = lines[i];
   133→    const isOrdered = /^\d+\.\s/.test(firstLine);
   134→    const baseIndent = firstLine.match(/^(\s*)/)[1].length;
   135→
   136→    while (i < lines.length) {
   137→      const line = lines[i];
   138→      if (line.trim() === '') {
   139→        i++;
   140→        break;
   141→      }
   142→
   143→      const indentMatch = line.match(/^(\s*)/);
   144→      const indent = indentMatch ? indentMatch[1].length : 0;
   145→
   146→      if (indent < baseIndent) break;
   147→
   148→      const ulMatch = line.match(/^(\s*)[-*+]\s+(.*)/);
   149→      const olMatch = line.match(/^(\s*)\d+\.\s+(.*)/);
   150→      const match = ulMatch || olMatch;
   151→
   152→      if (!match || match[1].length !== baseIndent) {
   153→        // 하위 항목이거나 다른 구조
   154→        if (indent > baseIndent && items.length > 0) {
   155→          const lastItem = items[items.length - 1];
   156→          const subResult = parseList(lines, i);
   157→          lastItem.children = subResult.html;
   158→          i = subResult.nextIndex;
   159→        } else {
   160→          break;
   161→        }
   162→        continue;
   163→      }
   164→
   165→      items.push({ text: match[2], children: null });
   166→      i++;
   167→
   168→      // 중첩 목록 확인
   169→      if (i < lines.length) {
   170→        const nextLine = lines[i];
   171→        const nextIndent = nextLine.match(/^(\s*)/)[1].length;
   172→        if (nextIndent > baseIndent && (nextLine.match(/^\s*[-*+]\s/) || nextLine.match(/^\s*\d+\.\s/))) {
   173→          const subResult = parseList(lines, i);
   174→          items[items.length - 1].children = subResult.html;
   175→          i = subResult.nextIndex;
   176→        }
   177→      }
   178→    }
   179→
   180→    const tag = isOrdered ? 'ol' : 'ul';
   181→    const html = `<${tag}>\n${items.map(item => {
   182→      const childContent = item.children ? `\n${item.children}` : '';
   183→      return `<li>${parseInline(item.text)}${childContent}</li>`;
   184→    }).join('\n')}\n</${tag}>`;
   185→
   186→    return { html, nextIndex: i };
   187→  }
   188→
   189→  // 인용문 파싱 (중첩 지원)
   190→  function parseBlockquote(lines, startIndex) {
   191→    const quoteLines = [];
   192→    let i = startIndex;
   193→
   194→    while (i < lines.length) {
   195→      const line = lines[i];
   196→      if (/^>/.test(line)) {
   197→        quoteLines.push(line.replace(/^>\s?/, ''));
   198→        i++;
   199→      } else if (line.trim() === '' && i + 1 < lines.length && /^>/.test(lines[i + 1])) {
   200→        quoteLines.push('');
   201→        i++;
   202→      } else {
   203→        break;
   204→      }
   205→    }
   206→
   207→    // 재귀적으로 인용문 내부 파싱
   208→    const innerHtml = parse(quoteLines.join('\n'));
   209→    return { html: `<blockquote>\n${innerHtml}\n</blockquote>`, nextIndex: i };
   210→  }
   211→
   212→  // 메인 파싱 함수
   213→  function parse(markdown) {
   214→    if (!markdown) return '';
   215→
   216→    // 줄 단위로 분리
   217→    const rawLines = markdown.split('\n');
   218→
   219→    // 코드블록 먼저 추출
   220→    const { lines, codeBlocks } = extractCodeBlocks(rawLines);
   221→
   222→    const outputParts = [];
   223→    let i = 0;
   224→    let paragraphLines = [];
   225→
   226→    function flushParagraph() {
   227→      if (paragraphLines.length === 0) return;
   228→      const content = paragraphLines.join('\n');
   229→      // 줄바꿈(두 스페이스+줄바꿈, 백슬래시+줄바꿈)을 플레이스홀더로 치환
   230→      // → parseInline 내부의 < 이스케이프가 <br> 을 건드리지 않도록 보호
   231→      const processed = content
   232→        .replace(/  \n/g, '\x00BR\x00\n')
   233→        .replace(/\\\n/g, '\x00BR\x00\n');
   234→      const parsed = parseInline(processed).replace(/\x00BR\x00/g, '<br>');
   235→      outputParts.push(`<p>${parsed}</p>`);
   236→      paragraphLines = [];
   237→    }
   238→
   239→    while (i < lines.length) {
   240→      const line = lines[i];
   241→
   242→      // 코드블록 플레이스홀더
   243→      if (/^\x00CODE_BLOCK_\d+\x00$/.test(line)) {
   244→        flushParagraph();
   245→        const idx = parseInt(line.match(/\d+/)[0]);
   246→        outputParts.push(codeBlocks[idx]);
   247→        i++;
   248→        continue;
   249→      }
   250→
   251→      // 빈 줄
   252→      if (line.trim() === '') {
   253→        flushParagraph();
   254→        i++;
   255→        continue;
   256→      }
   257→
   258→      // ATX 제목 (# ~ ######)
   259→      const headingMatch = line.match(/^(#{1,6})\s+(.+?)(?:\s+#+)?$/);
   260→      if (headingMatch) {
   261→        flushParagraph();
   262→        const level = headingMatch[1].length;
   263→        const text = headingMatch[2];
   264→        const id = text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
   265→        outputParts.push(`<h${level} id="${id}">${parseInline(text)}</h${level}>`);
   266→        i++;
   267→        continue;
   268→      }
   269→
   270→      // Setext 제목 (다음 줄이 === 또는 ---)
   271→      if (i + 1 < lines.length) {
   272→        const nextLine = lines[i + 1];
   273→        if (/^=+\s*$/.test(nextLine) && line.trim()) {
   274→          flushParagraph();
   275→          const id = line.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
   276→          outputParts.push(`<h1 id="${id}">${parseInline(line.trim())}</h1>`);
   277→          i += 2;
   278→          continue;
   279→        }
   280→        if (/^-+\s*$/.test(nextLine) && line.trim() && !(/^[-*+]\s/.test(line))) {
   281→          flushParagraph();
   282→          const id = line.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
   283→          outputParts.push(`<h2 id="${id}">${parseInline(line.trim())}</h2>`);
   284→          i += 2;
   285→          continue;
   286→        }
   287→      }
   288→
   289→      // 수평선 (---, ***, ___)
   290→      if (/^(\s*[-*_]){3,}\s*$/.test(line) && !(/^[-*+]\s/.test(line))) {
   291→        flushParagraph();
   292→        outputParts.push('<hr>');
   293→        i++;
   294→        continue;
   295→      }
   296→
   297→      // 인용문
   298→      if (/^>/.test(line)) {
   299→        flushParagraph();
   300→        const result = parseBlockquote(lines, i);
   301→        outputParts.push(result.html);
   302→        i = result.nextIndex;
   303→        continue;
   304→      }
   305→
   306→      // 목록
   307→      if (/^(\s*)[-*+]\s/.test(line) || /^(\s*)\d+\.\s/.test(line)) {
   308→        flushParagraph();
   309→        const result = parseList(lines, i);
   310→        outputParts.push(result.html);
   311→        i = result.nextIndex;
   312→        continue;
   313→      }
   314→
   315→      // 일반 텍스트 → 문단으로 수집
   316→      paragraphLines.push(line);
   317→      i++;
   318→    }
   319→
   320→    flushParagraph();
   321→
   322→    return outputParts.join('\n');
   323→  }
   324→
   325→  return { parse, parseInline, escapeHtml };
   326→})();
   327→

