     1→/**
     2→ * 에디터 로직
     3→ * - 실시간 미리보기 업데이트
     4→ * - 툴바 버튼 동작 (선택 텍스트 감싸기 / 커서 위치 삽입)
     5→ * - 드래그로 분할 창 크기 조정
     6→ * - 키보드 단축키 (Ctrl+B, Ctrl+I, Ctrl+K)
     7→ * - localStorage 자동 저장/복원
     8→ * - HTML 내보내기
     9→ */
    10→
    11→(function () {
    12→  'use strict';
    13→
    14→  // ===== DOM 요소 =====
    15→  const editor = document.getElementById('editor');
    16→  const preview = document.getElementById('preview');
    17→  const resizer = document.getElementById('resizer');
    18→  const editorPane = document.getElementById('editor-pane');
    19→  const previewPane = document.getElementById('preview-pane');
    20→  const editorContainer = document.getElementById('editor-container');
    21→  const exportBtn = document.getElementById('export-btn');
    22→  const saveStatus = document.getElementById('save-status');
    23→  const wordCount = document.getElementById('word-count');
    24→  const toast = document.getElementById('toast');
    25→
    26→  // ===== 상수 =====
    27→  const STORAGE_KEY = 'markdown-editor-content';
    28→  const SAVE_DEBOUNCE_MS = 800;
    29→  const PREVIEW_DEBOUNCE_MS = 150;
    30→  const MIN_PANE_WIDTH_PX = 80;
    31→
    32→  // ===== 초기 콘텐츠 =====
    33→  const DEFAULT_CONTENT = `# 마크다운 에디터에 오신 것을 환영합니다
    34→
    35→이것은 **라이브 미리보기**가 있는 마크다운 에디터입니다.
    36→
    37→## 사용법
    38→
    39→왼쪽 패널에서 마크다운을 작성하면 오른쪽에 실시간으로 렌더링됩니다.
    40→
    41→### 지원하는 서식
    42→
    43→- **굵게** \`**텍스트**\`
    44→- *기울임* \`*텍스트*\`
    45→- ***굵게+기울임*** \`***텍스트***\`
    46→- ~~취소선~~ \`~~텍스트~~\`
    47→- \`인라인 코드\`
    48→
    49→### 코드 블록
    50→
    51→\`\`\`javascript
    52→function greet(name) {
    53→  console.log(\`Hello, \${name}!\`);
    54→}
    55→greet('World');
    56→\`\`\`
    57→
    58→### 링크와 이미지
    59→
    60→[GitHub](https://github.com) 링크 예시
    61→
    62→### 목록
    63→
    64→1. 첫 번째 항목
    65→2. 두 번째 항목
    66→   - 중첩 항목 A
    67→   - 중첩 항목 B
    68→3. 세 번째 항목
    69→
    70→> 인용문 예시입니다.
    71→> 여러 줄도 지원합니다.
    72→
    73→---
    74→
    75→**Export HTML** 버튼으로 결과물을 다운로드할 수 있습니다.
    76→`;
    77→
    78→  // ===== 상태 =====
    79→  let saveTimer = null;
    80→  let previewTimer = null;
    81→  let isUnsaved = false;
    82→  let toastTimer = null;
    83→
    84→  // ===== 초기화 =====
    85→  function init() {
    86→    loadContent();
    87→    updatePreview();
    88→    updateWordCount();
    89→    setupToolbar();
    90→    setupResizer();
    91→    setupKeyboardShortcuts();
    92→    setupAutoSave();
    93→    setupExport();
    94→    setupScrollSync();
    95→  }
    96→
    97→  // ===== 콘텐츠 로드/저장 =====
    98→  function loadContent() {
    99→    try {
   100→      const saved = localStorage.getItem(STORAGE_KEY);
   101→      editor.value = saved !== null ? saved : DEFAULT_CONTENT;
   102→      setSaveStatus('saved');
   103→    } catch (e) {
   104→      editor.value = DEFAULT_CONTENT;
   105→    }
   106→  }
   107→
   108→  function saveContent() {
   109→    try {
   110→      localStorage.setItem(STORAGE_KEY, editor.value);
   111→      setSaveStatus('saved');
   112→      isUnsaved = false;
   113→    } catch (e) {
   114→      setSaveStatus('unsaved');
   115→      showToast('저장에 실패했습니다', 'error');
   116→    }
   117→  }
   118→
   119→  function setSaveStatus(status) {
   120→    if (!saveStatus) return;
   121→    if (status === 'saved') {
   122→      saveStatus.textContent = '저장됨';
   123→      saveStatus.className = 'saved';
   124→    } else if (status === 'unsaved') {
   125→      saveStatus.textContent = '저장 안 됨';
   126→      saveStatus.className = 'unsaved';
   127→    } else {
   128→      saveStatus.textContent = '저장 중...';
   129→      saveStatus.className = '';
   130→    }
   131→  }
   132→
   133→  // ===== 미리보기 업데이트 =====
   134→  function updatePreview() {
   135→    const markdown = editor.value;
   136→
   137→    if (!markdown.trim()) {
   138→      preview.innerHTML = `
   139→        <div id="preview-empty">
   140→          <div class="empty-icon">📝</div>
   141→          <p>왼쪽에 마크다운을 입력하면<br>여기에 미리보기가 표시됩니다</p>
   142→        </div>`;
   143→      return;
   144→    }
   145→
   146→    try {
   147→      preview.innerHTML = MarkdownParser.parse(markdown);
   148→    } catch (e) {
   149→      preview.innerHTML = `<p style="color: var(--accent-red)">파싱 오류: ${e.message}</p>`;
   150→    }
   151→  }
   152→
   153→  function schedulePreviewUpdate() {
   154→    clearTimeout(previewTimer);
   155→    previewTimer = setTimeout(updatePreview, PREVIEW_DEBOUNCE_MS);
   156→  }
   157→
   158→  // ===== 단어 수 계산 =====
   159→  function updateWordCount() {
   160→    if (!wordCount) return;
   161→    const text = editor.value.trim();
   162→    const chars = text.length;
   163→    const words = text ? text.split(/\s+/).filter(Boolean).length : 0;
   164→    const lines = editor.value.split('\n').length;
   165→    wordCount.textContent = `${lines}줄 · ${words}단어 · ${chars}자`;
   166→  }
