   168→  // ===== 자동 저장 설정 =====
   169→  function setupAutoSave() {
   170→    editor.addEventListener('input', () => {
   171→      isUnsaved = true;
   172→      setSaveStatus('unsaved');
   173→      schedulePreviewUpdate();
   174→      updateWordCount();
   175→
   176→      clearTimeout(saveTimer);
