   308→  function setupKeyboardShortcuts() {
   309→    editor.addEventListener('keydown', (e) => {
   310→      const isMac = navigator.platform.toUpperCase().includes('MAC');
   311→      const ctrl = isMac ? e.metaKey : e.ctrlKey;
   312→
   313→      if (!ctrl) return;
   314→
   315→      switch (e.key.toLowerCase()) {
   316→        case 'b':
   317→          e.preventDefault();
