   362→  // ===== 드래그 리사이저 =====
   363→  function setupResizer() {
   364→    if (!resizer) return;
   365→
   366→    let isDragging = false;
   367→    let startX = 0;
   368→    let startEditorWidth = 0;
   369→    let isVertical = false;
   370→
   371→    resizer.addEventListener('mousedown', onDragStart);
   372→    resizer.addEventListener('touchstart', onDragStart, { passive: false });
   373→
   374→    function onDragStart(e) {
   375→      isDragging = true;
   376→      resizer.classList.add('dragging');
   377→      document.body.style.cursor = 'col-resize';
   378→      document.body.style.userSelect = 'none';
   379→
   380→      const containerRect = editorContainer.getBoundingClientRect();
   381→      isVertical = containerRect.width < containerRect.height * 1.5 && window.innerWidth <= 768;
   382→
   383→      if (e.type === 'touchstart') {
   384→        startX = e.touches[0].clientX;
   385→      } else {
   386→        startX = e.clientX;
   387→        e.preventDefault();
   388→      }
   389→
   390→      startEditorWidth = editorPane.getBoundingClientRect().width;
   391→
   392→      document.addEventListener('mousemove', onDragMove);
   393→      document.addEventListener('mouseup', onDragEnd);
   394→      document.addEventListener('touchmove', onDragMove, { passive: false });
   395→      document.addEventListener('touchend', onDragEnd);
   396→    }
   397→
   398→    function onDragMove(e) {
   399→      if (!isDragging) return;
   400→      if (e.type === 'touchmove') e.preventDefault();
   401→
   402→      const clientX = e.type === 'touchmove' ? e.touches[0].clientX : e.clientX;
   403→      const delta = clientX - startX;
   404→      const containerWidth = editorContainer.getBoundingClientRect().width;
   405→      const resizerWidth = resizer.getBoundingClientRect().width;
   406→      const availableWidth = containerWidth - resizerWidth;
   407→
   408→      let newEditorWidth = startEditorWidth + delta;
   409→      newEditorWidth = Math.max(MIN_PANE_WIDTH_PX, Math.min(newEditorWidth, availableWidth - MIN_PANE_WIDTH_PX));
   410→
   411→      const editorPercent = (newEditorWidth / availableWidth) * 100;
   412→      const previewPercent = 100 - editorPercent;
   413→
   414→      editorPane.style.flex = 'none';
   415→      editorPane.style.width = `${editorPercent}%`;
   416→      previewPane.style.flex = 'none';
   417→      previewPane.style.width = `${previewPercent}%`;
   418→    }
   419→
   420→    function onDragEnd() {
   421→      isDragging = false;
   422→      resizer.classList.remove('dragging');
   423→      document.body.style.cursor = '';
   424→      document.body.style.userSelect = '';
   425→
   426→      document.removeEventListener('mousemove', onDragMove);
   427→      document.removeEventListener('mouseup', onDragEnd);
   428→      document.removeEventListener('touchmove', onDragMove);
   429→      document.removeEventListener('touchend', onDragEnd);
   430→    }
   431→
   432→    // 더블클릭으로 50/50 초기화
   433→    resizer.addEventListener('dblclick', () => {
   434→      editorPane.style.flex = '1';
   435→      editorPane.style.width = '';
   436→      previewPane.style.flex = '1';
   437→      previewPane.style.width = '';
   438→    });
   439→  }
