   442→  function setupScrollSync() {
   443→    let syncingEditor = false;
   444→    let syncingPreview = false;
   445→
   446→    editor.addEventListener('scroll', () => {
   447→      if (syncingEditor) return;
   448→      syncingPreview = true;
   449→
   450→      const editorScrollRatio = editor.scrollTop / (editor.scrollHeight - editor.clientHeight || 1);
   451→      const previewScrollMax = preview.scrollHeight - preview.clientHeight;
   452→      preview.scrollTop = editorScrollRatio * previewScrollMax;
   453→
   454→      requestAnimationFrame(() => { syncingPreview = false; });
   455→    });
   456→
   457→    preview.addEventListener('scroll', () => {
   458→      if (syncingPreview) return;
   459→      syncingEditor = true;
   460→
   461→      const previewScrollRatio = preview.scrollTop / (preview.scrollHeight - preview.clientHeight || 1);
   462→      const editorScrollMax = editor.scrollHeight - editor.clientHeight;
   463→      editor.scrollTop = previewScrollRatio * editorScrollMax;
   464→
   465→      requestAnimationFrame(() => { syncingEditor = false; });
   466→    });
   467→  }
